import { useNavigate } from "react-router-dom";
import { useState, useEffect } from "react";
import api from "../api/axios";
import "./styles/AddBook.css";

function AddBook() {
  const navigate = useNavigate();
  const genre = localStorage.getItem("genre");
  const role = localStorage.getItem("role");

  const [title, setTitle] = useState("");
  const [author, setAuthor] = useState("");
  const [imageURL, setImageURL] = useState("");
  const [about, setAbout] = useState("");
  const [authorInfo, setAuthorInfo] = useState("");
  const [message, setMessage] = useState("");

  // 🔐 Security check
  useEffect(() => {
    if (role !== "Librarian" || !genre) {
      navigate("/login", { replace: true });
    }
  }, [role, genre, navigate]);

  const handleAddBook = async () => {
    try {
      if (!title || !author || !imageURL || !about || !authorInfo) {
        return setMessage("Please fill all fields");
      }

      await api.post("/books/add", {
        title,
        author,
        imageURL,
        about,
        authorInfo,
        genre // 🔥 automatically uses librarian genre
      });

      setMessage("Book added successfully!");

      // Clear fields
      setTitle("");
      setAuthor("");
      setImageURL("");
      setAbout("");
      setAuthorInfo("");

    } catch (err) {
      setMessage(err.response?.data?.message || "Error adding book");
    }
  };

  return (
  <div className="addbook-page">

  <button className="back-btn" onClick={() => navigate(-1)}>
    ← Back
  </button>

  <h1 className="addbook-title">
    Add New <span>{genre}</span> Book
  </h1>

  <div className="addbook-card">

    <div className="form-row">
      <input
        type="text"
        placeholder="Book Title"
        value={title}
        onChange={(e) => setTitle(e.target.value)}
      />

      <input
        type="text"
        placeholder="Author"
        value={author}
        onChange={(e) => setAuthor(e.target.value)}
      />
    </div>

    <input
      type="text"
      placeholder="Cover Image URL"
      value={imageURL}
      onChange={(e) => setImageURL(e.target.value)}
      className="full-input"
    />

    <div className="form-row">
      <textarea
        placeholder="About the Book"
        value={about}
        onChange={(e) => setAbout(e.target.value)}
      />

      <textarea
        placeholder="About the Author"
        value={authorInfo}
        onChange={(e) => setAuthorInfo(e.target.value)}
      />
    </div>

    <input
      type="text"
      value={genre}
      disabled
      className="genre-input"
    />

    <button className="addbook-btn" onClick={handleAddBook}>
      ✨ Add Book
    </button>

    {message && <p className="success">{message}</p>}

  </div>
</div>
  );
}

export default AddBook;
